__kernel void compute_distances(__global const char *sandbox,
                                __global float *z,
                                const float target_lat,
                                const float target_long,
                                const int rec_count,
                                const int rec_length,
                                const int latitude_pos) {
    int i = get_global_id(0);
    if (i < rec_count) {
        const int base_idx = i * rec_length + latitude_pos - 1;
        // Convert latitude substring to float
        float tmp_lat = 0.0f;
        float tmp_long = 0.0f;

        // Parsing latitude: sandbox base_idx to base_idx+4 (5 chars)
        // and longitude: base_idx+5 to base_idx+9 (5 chars)
        // Because OpenMP code uses atof(rec_iter) and atof(rec_iter+5)
        // We replicate that by copying substrings and converting

        // Temporary buffers for lat and long strings
        char lat_str[16];
        char long_str[16];
        int j;

        // Copy latitude substring (5 chars) + null terminator
        for (j = 0; j < 5; j++) {
            lat_str[j] = sandbox[base_idx + j];
        }
        lat_str[5] = '\0';

        for (j = 0; j < 5; j++) {
            long_str[j] = sandbox[base_idx + 5 + j];
        }
        long_str[5] = '\0';

        // Convert to float
        tmp_lat = atof(lat_str);
        tmp_long = atof(long_str);

        float dlat = tmp_lat - target_lat;
        float dlong = tmp_long - target_long;
        z[i] = sqrt(dlat * dlat + dlong * dlong);
    }
}
